// Merge thresholds config and generate-idea agent prompt
// Uses $input.all() to get both merged items from parallel fetches
const allItems = $input.all();

let thresholdsConfig = null;
let generateIdeaPrompt = null;

for (const item of allItems) {
  const data = item.json;
  // Identify thresholds config by presence of runtime/ideas/publishing sections
  if (data.runtime || data.ideas || data.publishing || data.ingestion) {
    thresholdsConfig = data;
  }
  // Identify agent prompt by presence of content field
  else if (data.content && data.name === 'generate-idea') {
    generateIdeaPrompt = data;
  }
  else if (data.content) {
    // Fallback: assume it's the agent prompt
    generateIdeaPrompt = data;
  }
}

if (!thresholdsConfig) {
  console.log('Warning: Could not find thresholds config');
  thresholdsConfig = { runtime: { use_stubs: true }, ideas: {} };
}

if (!generateIdeaPrompt) {
  console.log('Warning: Could not find generate-idea agent prompt');
  generateIdeaPrompt = { content: '' };
}

return [{
  json: {
    ...thresholdsConfig,
    _agents: {
      generateIdea: generateIdeaPrompt.content
    }
  }
}];

// Calculate date range for idea generation
// Uses config values from merged config + agents

const merged = $input.first().json;
const ideasConfig = merged.ideas || {};
const agents = merged._agents;
const runtime = merged.runtime || { use_stubs: true };

// Get thresholds from config
const minRelevanceScore = ideasConfig.min_relevance_for_idea || 80;
const minFeasibility = ideasConfig.min_feasibility || 50;
const minImpact = ideasConfig.min_impact || 50;
const lookbackDays = ideasConfig.lookback_days || 7;

const now = new Date();

const periodEnd = new Date(now);
periodEnd.setUTCHours(23, 59, 59, 999);

const periodStart = new Date(now);
periodStart.setUTCDate(periodStart.getUTCDate() - lookbackDays);
periodStart.setUTCHours(0, 0, 0, 0);

// Format dates for SQL query
const formatDateSQL = (d) => d.toISOString();

console.log(`Using thresholds from config: minRelevanceScore=${minRelevanceScore}, minFeasibility=${minFeasibility}, minImpact=${minImpact}, lookbackDays=${lookbackDays}`);
console.log(`Loaded generate-idea agent prompt: ${agents?.generateIdea?.length || 0} chars`);
console.log(`Runtime mode: use_stubs=${runtime.use_stubs}`);

return [{
  json: {
    periodStartSQL: formatDateSQL(periodStart),
    periodEndSQL: formatDateSQL(periodEnd),
    generatedAt: now.toISOString(),
    minRelevanceScore,
    _thresholds: {
      runtime: runtime,
      minRelevanceScore,
      minFeasibility,
      minImpact,
      lookbackDays
    },
    _agents: agents
  }
}];

// Merge insights with period data and check if we have any
const insights = $input.all().map(item => item.json);
const periodData = $('Calculate Period').first().json;
const agents = periodData._agents;
const thresholds = periodData._thresholds;

// Filter out empty results (when query returns no rows)
const validInsights = insights.filter(i => i.id);

if (validInsights.length === 0) {
  return [{
    json: {
      ...periodData,
      insights: [],
      insightCount: 0,
      hasInsights: false,
      _agents: agents,
      _thresholds: thresholds
    }
  }];
}

return [{
  json: {
    ...periodData,
    insights: validInsights,
    insightCount: validInsights.length,
    hasInsights: true,
    _agents: agents,
    _thresholds: thresholds
  }
}];

// Format all insights for Claude - NO CLUSTERING
// Single call with all insights enables cross-topic pattern detection
const data = $input.first().json;
const insights = data.insights || [];
const thresholds = data._thresholds || {};
const agents = data._agents || {};

// Format insights array (lean fields only, matching generate-idea.md input spec)
const formattedInsights = insights.map(i => ({
  id: i.id,
  title: i.title,
  tldr: i.tldr,
  bullets: i.summary_bullets || [],
  topics: i.topics || [],
  geo: i.geo || [],
  score: i.freedom_relevance_score
}));

// Collect all insight data needed for downstream processing
const allInsightIds = insights.map(i => i.id);
const allCitations = [];
for (const insight of insights) {
  if (insight.citations && Array.isArray(insight.citations)) {
    allCitations.push(...insight.citations);
  }
}
const uniqueCitations = [...new Set(allCitations)];

console.log(`Formatted ${formattedInsights.length} insights for Claude (no clustering)`);

return [{
  json: {
    prompt: agents.generateIdea,
    insightCount: formattedInsights.length,
    insights: formattedInsights,
    _rawInsights: insights,
    _allInsightIds: allInsightIds,
    _allCitations: uniqueCitations,
    _periodData: {
      generatedAt: data.generatedAt,
      periodStartSQL: data.periodStartSQL,
      periodEndSQL: data.periodEndSQL
    },
    _thresholds: thresholds,
    _agents: agents
  }
}];

// STUB: IdeaSynthesizer Agent
// Simulates Claude API response with ideas[] and patterns_observed[] arrays
// Replace with real HTTP Request to Claude API when ready

const input = $input.first().json;
const insights = input.insights || [];
const thresholds = input._thresholds || {};
const periodData = input._periodData;

if (insights.length === 0) {
  return [{
    json: {
      content: [{ type: 'text', text: JSON.stringify({ ideas: [], patterns_observed: [] }) }],
      _periodData: periodData,
      _rawInsights: input._rawInsights,
      _allInsightIds: input._allInsightIds,
      _allCitations: input._allCitations,
      _thresholds: thresholds,
      _agents: input._agents
    }
  }];
}

// Group insights by primary topic for stub idea generation
const topicGroups = {};
for (const insight of insights) {
  const primaryTopic = (insight.topics && insight.topics[0]) || 'general';
  if (!topicGroups[primaryTopic]) {
    topicGroups[primaryTopic] = [];
  }
  topicGroups[primaryTopic].push(insight);
}

const topicDisplayNames = {
  'bitcoin': 'Bitcoin & Payments',
  'zk': 'Zero Knowledge Technology',
  'censorship-resistance': 'Censorship Resistance',
  'comms': 'Secure Communications',
  'payments': 'Payment Systems',
  'identity': 'Identity & Privacy',
  'privacy': 'Privacy Tools',
  'surveillance': 'Anti-Surveillance',
  'activism': 'Activism Tools',
  'sovereignty': 'Digital Sovereignty'
};

// Generate 1-3 stub ideas based on topic groups
const ideas = [];
const topics = Object.keys(topicGroups).slice(0, 3); // Max 3 ideas

for (const topic of topics) {
  const topicInsights = topicGroups[topic];
  const topicName = topicDisplayNames[topic] || topic;
  const insightIds = topicInsights.map(i => i.id);
  const insightTldrs = topicInsights.slice(0, 3).map(i => i.tldr).join(' ');
  const avgScore = Math.round(topicInsights.reduce((sum, i) => sum + i.score, 0) / topicInsights.length);

  const feasibilityScore = Math.min(100, Math.max(40, 60 + Math.floor(Math.random() * 30)));
  const impactScore = Math.min(100, Math.max(40, avgScore - 10 + Math.floor(Math.random() * 20)));

  ideas.push({
    derived_from_insight_ids: insightIds,
    detected_pattern: `${topicInsights.length} signals in ${topicName} suggest tooling gaps for activists`,
    problem_statement: `Based on ${topicInsights.length} signals in ${topicName}, there is a clear need for improved tooling. Key observations: ${insightTldrs}`,
    threat_model: `Adversaries include state-level actors with network monitoring capabilities, platform operators with content moderation powers, and sophisticated attackers targeting ${topicName.toLowerCase()} infrastructure.`,
    affected_groups: [
      'Activists in regions with internet censorship',
      'Journalists protecting sources',
      'Human rights organizations',
      `Users of ${topicName.toLowerCase()} tools under surveillance`
    ],
    proposed_solution: `Develop a ${topicName.toLowerCase()} enhancement that addresses the gaps identified. Focus on: (1) improving usability for non-technical users, (2) adding offline/low-bandwidth support, (3) implementing defense-in-depth.`,
    mvp_scope: `Phase 1: Build proof-of-concept demonstrating core ${topic} functionality with basic UI. Include: CLI interface, config file support, basic docs, and integration tests.`,
    misuse_risks: `Could be misused for: (1) evading legitimate law enforcement, (2) coordinating harmful activities, (3) spreading misinformation. Mitigations: transparency reporting, voluntary identity binding, clear usage guidelines.`,
    feasibility_score: feasibilityScore,
    impact_score: impactScore,
    technical_dependencies: [
      'Cryptographic libraries (libsodium or equivalent)',
      'Networking stack with proxy support',
      'Cross-platform runtime (Rust or Go preferred)'
    ],
    suggested_stack: ['Rust for core', 'TypeScript for web', 'SQLite for local storage', 'libp2p for P2P'],
    prior_art: ['Tor Project', 'Signal Protocol', 'Briar Messenger', 'Lokinet'],
    open_questions: [
      'Minimum viable UX for non-technical users?',
      'Key management without trusted third parties?',
      'Priority jurisdictions for initial deployment?'
    ]
  });
}

// Generate patterns_observed for topics with only 1 insight (not enough for idea)
const patternsObserved = [];
for (const [topic, topicInsights] of Object.entries(topicGroups)) {
  if (topicInsights.length === 1 && !topics.includes(topic)) {
    patternsObserved.push({
      pattern: `Single signal in ${topicDisplayNames[topic] || topic}`,
      insight_ids: topicInsights.map(i => i.id),
      reason_no_idea: 'Single data point - need more signals to identify generalizable solution'
    });
  }
}

const output = { ideas, patterns_observed: patternsObserved };

console.log(`[STUB] Generated ${ideas.length} ideas, ${patternsObserved.length} patterns observed`);

return [{
  json: {
    content: [{ type: 'text', text: JSON.stringify(output) }],
    _periodData: periodData,
    _rawInsights: input._rawInsights,
    _allInsightIds: input._allInsightIds,
    _allCitations: input._allCitations,
    _thresholds: thresholds,
    _agents: input._agents
  }
}];

// Process real Claude API response and add pass-through data
const claudeResponse = $input.first().json;
const inputData = $('Use Stubs for IdeaSynthesizer?').first().json;
const thresholds = inputData._thresholds || {};
const periodData = inputData._periodData;

return [{
  json: {
    content: claudeResponse.content,
    _periodData: periodData,
    _rawInsights: inputData._rawInsights,
    _allInsightIds: inputData._allInsightIds,
    _allCitations: inputData._allCitations,
    _thresholds: thresholds,
    _agents: inputData._agents
  }
}];

// Parse and validate LLM output for project ideas
// Handles { ideas[], patterns_observed[] } format from generate-idea.md
const input = $input.first().json;
const thresholds = input._thresholds || {};
const minFeasibility = thresholds.minFeasibility || 50;
const minImpact = thresholds.minImpact || 50;

let parsed;
try {
  let text = input.content[0].text.trim();

  // Strip markdown code blocks if present
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '');
  }

  parsed = JSON.parse(text);
} catch (e) {
  console.log('Parse error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 500));
  return [{
    json: {
      ideas: [],
      passingIdeas: [],
      filteredIdeas: [],
      invalidIdeas: [{ error: 'JSON parse failed: ' + e.message }],
      patternsObserved: [],
      _periodData: input._periodData,
      _rawInsights: input._rawInsights,
      _allCitations: input._allCitations,
      _thresholds: thresholds
    }
  }];
}

// Ensure arrays exist
if (!Array.isArray(parsed.ideas)) parsed.ideas = [];
if (!Array.isArray(parsed.patterns_observed)) parsed.patterns_observed = [];

// Validate each idea
const validIdeas = [];
const invalidIdeas = [];

for (const idea of parsed.ideas) {
  const errors = [];

  // Required fields per generate-idea.md
  const required = [
    'derived_from_insight_ids', 'detected_pattern', 'problem_statement',
    'threat_model', 'affected_groups', 'proposed_solution',
    'mvp_scope', 'misuse_risks', 'feasibility_score', 'impact_score'
  ];

  for (const field of required) {
    if (idea[field] === undefined || idea[field] === null || idea[field] === '') {
      errors.push(`Missing: ${field}`);
    }
  }

  // Score validation
  if (typeof idea.feasibility_score !== 'number' || idea.feasibility_score < 0 || idea.feasibility_score > 100) {
    errors.push('Invalid feasibility_score (must be 0-100)');
  }
  if (typeof idea.impact_score !== 'number' || idea.impact_score < 0 || idea.impact_score > 100) {
    errors.push('Invalid impact_score (must be 0-100)');
  }

  // Array validations
  if (!Array.isArray(idea.derived_from_insight_ids) || idea.derived_from_insight_ids.length === 0) {
    errors.push('derived_from_insight_ids must be non-empty array');
  }
  if (!Array.isArray(idea.affected_groups) || idea.affected_groups.length === 0) {
    errors.push('affected_groups must be non-empty array');
  }

  if (errors.length === 0) {
    // Normalize optional array fields
    idea.technical_dependencies = idea.technical_dependencies || [];
    idea.suggested_stack = idea.suggested_stack || [];
    idea.prior_art = idea.prior_art || [];
    idea.open_questions = idea.open_questions || [];
    validIdeas.push(idea);
  } else {
    invalidIdeas.push({ idea, errors });
  }
}

// Filter valid ideas by threshold
const passingIdeas = [];
const filteredIdeas = [];

for (const idea of validIdeas) {
  if (idea.feasibility_score >= minFeasibility && idea.impact_score >= minImpact) {
    passingIdeas.push(idea);
  } else {
    filteredIdeas.push({
      idea,
      reason: `Scores below threshold (f:${idea.feasibility_score} < ${minFeasibility} or i:${idea.impact_score} < ${minImpact})`
    });
  }
}

console.log(`Parsed ${parsed.ideas.length} ideas: ${validIdeas.length} valid, ${invalidIdeas.length} invalid`);
console.log(`Threshold filter: ${passingIdeas.length} passing, ${filteredIdeas.length} filtered`);
console.log(`Patterns observed: ${parsed.patterns_observed.length}`);

return [{
  json: {
    passingIdeas,
    filteredIdeas,
    invalidIdeas,
    patternsObserved: parsed.patterns_observed,
    totalIdeasParsed: parsed.ideas.length,
    _periodData: input._periodData,
    _rawInsights: input._rawInsights,
    _allCitations: input._allCitations,
    _thresholds: thresholds,
    _usedThresholds: { minFeasibility, minImpact }
  }
}];

// Split passing ideas into individual items for loop processing
// Also log patterns_observed for observability
const data = $input.first().json;
const passingIdeas = data.passingIdeas || [];
const patternsObserved = data.patternsObserved || [];

// Log patterns for observability (could store in DB in future)
if (patternsObserved.length > 0) {
  console.log('=== Patterns Observed (not actionable yet) ===');
  for (const pattern of patternsObserved) {
    console.log(`- ${pattern.pattern}`);
    console.log(`  Insights: ${pattern.insight_ids?.join(', ')}`);
    console.log(`  Reason no idea: ${pattern.reason_no_idea}`);
  }
}

// Return each passing idea as a separate item
const items = passingIdeas.map((idea, index) => ({
  json: {
    idea,
    ideaIndex: index,
    totalIdeas: passingIdeas.length,
    _periodData: data._periodData,
    _rawInsights: data._rawInsights,
    _allCitations: data._allCitations,
    _thresholds: data._thresholds
  }
}));

console.log(`Splitting ${passingIdeas.length} ideas into individual items for processing`);

return items;

// Build INSERT query for project_ideas table
const data = $input.first().json;
const idea = data.idea;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

function formatUuidArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  return "'{" + arr.join(',') + "}'";
}

const query = `INSERT INTO project_ideas (
  derived_from_insight_ids,
  detected_pattern,
  problem_statement,
  threat_model,
  affected_groups,
  proposed_solution,
  mvp_scope,
  misuse_risks,
  feasibility_score,
  impact_score,
  technical_dependencies,
  suggested_stack,
  prior_art,
  open_questions,
  status
) VALUES (
  ${formatUuidArray(idea.derived_from_insight_ids)},
  ${escapeStr(idea.detected_pattern)},
  ${escapeStr(idea.problem_statement)},
  ${escapeStr(idea.threat_model)},
  ${formatPgArray(idea.affected_groups)},
  ${escapeStr(idea.proposed_solution)},
  ${escapeStr(idea.mvp_scope)},
  ${escapeStr(idea.misuse_risks)},
  ${idea.feasibility_score},
  ${idea.impact_score},
  ${formatPgArray(idea.technical_dependencies)},
  ${formatPgArray(idea.suggested_stack)},
  ${formatPgArray(idea.prior_art)},
  ${formatPgArray(idea.open_questions)},
  'new'
) RETURNING id, feasibility_score, impact_score, created_at`;

return [{
  json: {
    query,
    _ideaData: {
      idea,
      ideaIndex: data.ideaIndex,
      totalIdeas: data.totalIdeas
    },
    _periodData: data._periodData,
    _rawInsights: data._rawInsights,
    _allCitations: data._allCitations,
    _thresholds: data._thresholds
  }
}];

// Merge insert result with idea data for issue creation
const insertResult = $input.first().json;
const buildData = $('Build Idea Query').first().json;
const ideaData = buildData._ideaData;
const thresholds = buildData._thresholds || {};
const rawInsights = buildData._rawInsights || [];

// Find the insights that this idea derives from
const derivedInsights = rawInsights.filter(i => 
  ideaData.idea.derived_from_insight_ids.includes(i.id)
);

return [{
  json: {
    ideaId: insertResult.id,
    feasibilityScore: insertResult.feasibility_score,
    impactScore: insertResult.impact_score,
    createdAt: insertResult.created_at,
    idea: ideaData.idea,
    ideaIndex: ideaData.ideaIndex,
    totalIdeas: ideaData.totalIdeas,
    derivedInsights,
    _thresholds: thresholds
  }
}];

// Prepare GitHub issue title and body
// Uses actual published_url from insights when available

const data = $input.first().json;
const idea = data.idea;
const derivedInsights = data.derivedInsights || [];
const thresholds = data._thresholds || {};

// Build issue title (truncate cleanly at word boundary)
let titleText = idea.detected_pattern || idea.problem_statement;
if (titleText.length > 80) {
  titleText = titleText.substring(0, 77).replace(/\s+\S*$/, '') + '...';
}
const issueTitle = `[Idea] ${titleText}`;

// Build issue body markdown
const affectedGroupsList = idea.affected_groups.map(g => `- ${g}`).join('\n');
const dependenciesList = (idea.technical_dependencies || []).map(d => `- ${d}`).join('\n') || '_None specified_';
const stackList = (idea.suggested_stack || []).map(s => `- ${s}`).join('\n') || '_None specified_';
const priorArtList = (idea.prior_art || []).map(p => `- ${p}`).join('\n') || '_None specified_';
const questionsList = (idea.open_questions || []).map(q => `- ${q}`).join('\n') || '_None specified_';

// Build derived insights links using actual published_url
let insightLinks = '_No insights linked_';
if (derivedInsights.length > 0) {
  insightLinks = derivedInsights.map(insight => {
    const url = insight.published_url || `https://libertas.fgu.tech/signals/${insight.id}`;
    return `- [${insight.title}](${url})`;
  }).join('\n');
}

const issueBody = `## Detected Pattern

${idea.detected_pattern}

## Problem Statement

${idea.problem_statement}

## Threat Model

${idea.threat_model}

## Affected Groups

${affectedGroupsList}

## Proposed Solution

${idea.proposed_solution}

## MVP Scope

${idea.mvp_scope}

## Misuse Risks

${idea.misuse_risks}

## Scores

- **Feasibility:** ${idea.feasibility_score}/100
- **Impact:** ${idea.impact_score}/100

## Technical Dependencies

${dependenciesList}

## Suggested Stack

${stackList}

## Prior Art

${priorArtList}

## Open Questions

${questionsList}

## Derived From Insights

${insightLinks}

---
*Auto-generated by Libertas Workflow D*
*Idea ID: \`${data.ideaId}\`*`;

return [{
  json: {
    issueTitle,
    issueBody,
    ideaId: data.ideaId,
    feasibilityScore: data.feasibilityScore,
    impactScore: data.impactScore,
    ideaIndex: data.ideaIndex,
    totalIdeas: data.totalIdeas,
    _thresholds: thresholds
  }
}];

// STUB: Simulate GitHub issue creation response
const data = $input.first().json;

const stubIssueNumber = 100 + Math.floor(Math.random() * 900);
const stubIssueUrl = `https://github.com/FGUTech/libertas/issues/${stubIssueNumber}`;

console.log(`[STUB] Created mock GitHub issue #${stubIssueNumber} for idea ${data.ideaId}`);

return [{
  json: {
    html_url: stubIssueUrl,
    number: stubIssueNumber,
    title: data.issueTitle,
    state: 'open',
    _ideaId: data.ideaId,
    _ideaIndex: data.ideaIndex,
    _totalIdeas: data.totalIdeas,
    _isStub: true
  }
}];

// Process real GitHub API response
const githubResponse = $input.first().json;
const prepareData = $('Prepare GitHub Issue').first().json;

return [{
  json: {
    html_url: githubResponse.html_url,
    number: githubResponse.number,
    title: githubResponse.title,
    state: githubResponse.state,
    _ideaId: prepareData.ideaId,
    _ideaIndex: prepareData.ideaIndex,
    _totalIdeas: prepareData.totalIdeas,
    _isStub: false
  }
}];

// Handle errors from GitHub API call
const error = $input.first().json;
const prepareData = $('Prepare GitHub Issue').first().json;

console.log('GitHub API error:', JSON.stringify(error));

return [{
  json: {
    html_url: null,
    number: null,
    title: prepareData.issueTitle,
    state: 'error',
    _ideaId: prepareData.ideaId,
    _ideaIndex: prepareData.ideaIndex,
    _totalIdeas: prepareData.totalIdeas,
    _isStub: false,
    _apiError: true,
    _errorMessage: 'GitHub issue creation failed - will retry later'
  }
}];

// Build UPDATE query to set github_issue_url on the project idea
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

const issueUrl = data.html_url;

const query = `UPDATE project_ideas 
SET github_issue_url = ${escapeStr(issueUrl)},
    updated_at = NOW()
WHERE id = ${escapeStr(data._ideaId)}::uuid
RETURNING id, github_issue_url`;

console.log(`Updating idea ${data._ideaId} with GitHub issue URL: ${issueUrl || 'NULL'}`);

return [{
  json: {
    query,
    _issueData: data
  }
}];

// Summary for each processed idea (loops back to SplitInBatches)
const updateResult = $input.first().json;
const issueData = $('Build Update Query').first().json._issueData;

console.log(`Processed idea ${issueData._ideaIndex + 1}/${issueData._totalIdeas}: ${updateResult.github_issue_url || 'no URL'}`);

return [{
  json: {
    success: true,
    ideaId: updateResult.id,
    githubIssueUrl: updateResult.github_issue_url,
    githubIssueNumber: issueData.number,
    ideaIndex: issueData._ideaIndex,
    totalIdeas: issueData._totalIdeas,
    wasStub: issueData._isStub,
    hadError: issueData._apiError || false,
    processedAt: new Date().toISOString()
  }
}];

// Final workflow summary - aggregates all processed ideas
const items = $input.all();

const results = items.map(item => item.json);
const successful = results.filter(r => r.success && !r.hadError);
const errors = results.filter(r => r.hadError);

console.log(`\n=== Workflow D Complete ===`);
console.log(`Ideas created: ${successful.length}`);
console.log(`Errors: ${errors.length}`);
for (const s of successful) {
  console.log(`  - ${s.githubIssueUrl}`);
}

return [{
  json: {
    executedAt: new Date().toISOString(),
    success: true,
    ideasCreated: successful.length,
    ideasWithErrors: errors.length,
    githubIssues: successful.map(s => s.githubIssueUrl).filter(Boolean),
    results
  }
}];

// Log when no ideas pass thresholds
const data = $input.first().json;
const thresholds = data._usedThresholds || {};

console.log(`No ideas passed threshold check.`);
console.log(`Thresholds: feasibility >= ${thresholds.minFeasibility}, impact >= ${thresholds.minImpact}`);
console.log(`Total ideas parsed: ${data.totalIdeasParsed}`);
console.log(`Filtered: ${data.filteredIdeas?.length || 0}`);
console.log(`Invalid: ${data.invalidIdeas?.length || 0}`);

if (data.patternsObserved?.length > 0) {
  console.log(`Patterns observed: ${data.patternsObserved.length}`);
  for (const p of data.patternsObserved) {
    console.log(`  - ${p.pattern}`);
  }
}

return [{
  json: {
    executedAt: new Date().toISOString(),
    success: true,
    skipped: true,
    reason: 'No ideas passed threshold check',
    totalIdeasParsed: data.totalIdeasParsed,
    filteredCount: data.filteredIdeas?.length || 0,
    invalidCount: data.invalidIdeas?.length || 0,
    patternsObservedCount: data.patternsObserved?.length || 0,
    usedThresholds: thresholds
  }
}];

// Handle case when no high-signal insights were found
const data = $input.first().json;
const thresholds = data._thresholds || {};

console.log(`No high-signal insights found for idea generation.`);
console.log(`Criteria: freedom_relevance_score >= ${data.minRelevanceScore}, status = published, last ${thresholds.lookbackDays || 7} days, not already used.`);

return [{
  json: {
    executedAt: new Date().toISOString(),
    success: true,
    skipped: true,
    reason: 'No eligible high-signal insights found',
    criteria: {
      minRelevanceScore: data.minRelevanceScore,
      periodStartSQL: data.periodStartSQL,
      periodEndSQL: data.periodEndSQL,
      lookbackDays: thresholds.lookbackDays || 7
    }
  }
}];
